package com.example.mfa.service;

import com.example.mfa.model.AppUser;
import com.example.mfa.repository.AppUserRepository;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class UserService {

    private final AppUserRepository appUserRepository;
    private final PasswordEncoder passwordEncoder;

    public UserService(AppUserRepository appUserRepository, PasswordEncoder passwordEncoder) {
        this.appUserRepository = appUserRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public AppUser register(String username, String password) {
        appUserRepository.findByUsername(username).ifPresent(u -> {
            throw new IllegalArgumentException("Username already exists");
        });
        AppUser user = new AppUser();
        user.setUsername(username);
        user.setPasswordHash(passwordEncoder.encode(password));
        return appUserRepository.save(user);
    }

    public AppUser getByUsername(String username) {
        return appUserRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
    }

    public boolean verifyPassword(AppUser user, String rawPassword) {
        return passwordEncoder.matches(rawPassword, user.getPasswordHash());
    }

    @Transactional
    public AppUser save(AppUser user) {
        return appUserRepository.save(user);
    }
}

package com.example.mfa.service;

import com.example.mfa.model.AppUser;
import com.example.mfa.model.BackupCode;
import com.example.mfa.repository.BackupCodeRepository;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {

    private static final int DEFAULT_CODE_COUNT = 10;
    private static final int CODE_LENGTH = 10;
    private static final String ALPHABET = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    public BackupCodeService(BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> generateAndStoreCodes(AppUser user) {
        backupCodeRepository.deleteByUser(user);
        List<String> plainCodes = new ArrayList<>();
        for (int i = 0; i < DEFAULT_CODE_COUNT; i++) {
            String code = generateCode();
            BackupCode backupCode = new BackupCode();
            backupCode.setUser(user);
            backupCode.setCodeHash(passwordEncoder.encode(code));
            backupCode.setUsed(false);
            backupCodeRepository.save(backupCode);
            plainCodes.add(formatCode(code));
        }
        return plainCodes;
    }

    @Transactional
    public boolean consumeBackupCode(AppUser user, String rawCode) {
        String normalized = normalize(rawCode);
        List<BackupCode> codes = backupCodeRepository.findByUserAndUsedFalse(user);
        for (BackupCode code : codes) {
            if (passwordEncoder.matches(normalized, code.getCodeHash())) {
                code.setUsed(true);
                code.setUsedAt(Instant.now());
                backupCodeRepository.save(code);
                return true;
            }
        }
        return false;
    }

    private String generateCode() {
        StringBuilder sb = new StringBuilder(CODE_LENGTH);
        for (int i = 0; i < CODE_LENGTH; i++) {
            sb.append(ALPHABET.charAt(secureRandom.nextInt(ALPHABET.length())));
        }
        return sb.toString();
    }

    private String formatCode(String code) {
        return code.substring(0, 5) + "-" + code.substring(5);
    }

    private String normalize(String code) {
        return code == null ? "" : code.replace("-", "").replace(" ", "").trim().toUpperCase();
    }
}

package com.example.mfa.service;

import com.example.mfa.dto.AuthResponse;
import com.example.mfa.model.AppUser;
import com.example.mfa.model.MfaMethod;
import org.springframework.stereotype.Service;

@Service
public class AuthService {

    private final UserService userService;
    private final BackupCodeService backupCodeService;

    public AuthService(UserService userService, BackupCodeService backupCodeService) {
        this.userService = userService;
        this.backupCodeService = backupCodeService;
    }

    public AuthResponse login(String username, String password) {
        AppUser user = userService.getByUsername(username);
        if (!userService.verifyPassword(user, password)) {
            return new AuthResponse(false, false, "Invalid credentials", null);
        }
        if (user.isTwoFactorEnabled()) {
            return new AuthResponse(false, true, "MFA required", null);
        }
        return new AuthResponse(true, false, "Authenticated", null);
    }

    public AuthResponse authenticateWithBackupCode(String username, String code) {
        AppUser user = userService.getByUsername(username);
        if (!user.isTwoFactorEnabled()) {
            return new AuthResponse(false, false, "MFA is not enabled", null);
        }
        boolean consumed = backupCodeService.consumeBackupCode(user, code);
        if (!consumed) {
            return new AuthResponse(false, true, "Invalid backup code", MfaMethod.BACKUP_CODE);
        }
        return new AuthResponse(true, false, "Authenticated with backup code", MfaMethod.BACKUP_CODE);
    }
}

package com.example.mfa.service;

import com.example.mfa.model.AppUser;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
public class MfaService {

    private final UserService userService;
    private final BackupCodeService backupCodeService;

    public MfaService(UserService userService, BackupCodeService backupCodeService) {
        this.userService = userService;
        this.backupCodeService = backupCodeService;
    }

    @Transactional
    public List<String> enableMfa(String username, String totpSecret) {
        AppUser user = userService.getByUsername(username);
        user.setTwoFactorEnabled(true);
        user.setTotpSecret(totpSecret);
        userService.save(user);
        return backupCodeService.generateAndStoreCodes(user);
    }

    @Transactional
    public List<String> regenerateBackupCodes(String username) {
        AppUser user = userService.getByUsername(username);
        if (!user.isTwoFactorEnabled()) {
            throw new IllegalStateException("MFA is not enabled");
        }
        return backupCodeService.generateAndStoreCodes(user);
    }
}

package com.example.mfa.controller;

import com.example.mfa.dto.*;
import com.example.mfa.service.AuthService;
import com.example.mfa.service.MfaService;
import com.example.mfa.service.UserService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final UserService userService;
    private final AuthService authService;
    private final MfaService mfaService;

    public AuthController(UserService userService, AuthService authService, MfaService mfaService) {
        this.userService = userService;
        this.authService = authService;
        this.mfaService = mfaService;
    }

    @PostMapping("/register")
    public ResponseEntity<?> register(@RequestBody RegisterRequest request) {
        userService.register(request.getUsername(), request.getPassword());
        return ResponseEntity.status(HttpStatus.CREATED).body("User registered");
    }

    @PostMapping("/login")
    public ResponseEntity<AuthResponse> login(@RequestBody LoginRequest request) {
        return ResponseEntity.ok(authService.login(request.getUsername(), request.getPassword()));
    }

    @PostMapping("/mfa/enable")
    public ResponseEntity<BackupCodesResponse> enableMfa(@RequestBody EnableMfaRequest request) {
        return ResponseEntity.ok(new BackupCodesResponse(
                request.getUsername(),
                mfaService.enableMfa(request.getUsername(), request.getTotpSecret())
        ));
    }

    @PostMapping("/mfa/backup-code")
    public ResponseEntity<AuthResponse> authenticateWithBackupCode(@RequestBody MfaVerifyRequest request) {
        return ResponseEntity.ok(authService.authenticateWithBackupCode(request.getUsername(), request.getCode()));
    }

    @PostMapping("/mfa/backup-codes/regenerate")
    public ResponseEntity<BackupCodesResponse> regenerateBackupCodes(@RequestParam String username) {
        return ResponseEntity.ok(new BackupCodesResponse(
                username,
                mfaService.regenerateBackupCodes(username)
        ));
    }
}

